TextEmbeddingParam param = TextEmbeddingParam
.builder()
.model("multimodal-embedding-v1") 
.texts(Arrays.asList("衣服的质量杠杠的，很漂亮，不枉我等了这么久啊，喜欢，以后还来这里买")) 
.build();
TextEmbedding textEmbedding = new TextEmbedding();
